import{_ as o,o as l,c as i,ai as a}from"./chunks/framework.ampVZV4B.js";const m=JSON.parse('{"title":"社交寒暄口语模板","description":"","frontmatter":{},"headers":[],"relativePath":"english-speaking/templates-social.md","filePath":"english-speaking/templates-social.md"}'),d={name:"english-speaking/templates-social.md"};function t(c,e,n,r,s,h){return l(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="社交寒暄口语模板" tabindex="-1">社交寒暄口语模板 <a class="header-anchor" href="#社交寒暄口语模板" aria-label="Permalink to “社交寒暄口语模板”">​</a></h1><blockquote><p>这一篇适合初次见面、轻松交流、聊天破冰、发出邀请、礼貌回应。<br> 社交口语的重点是：<strong>自然、轻松、不要太书面</strong>。</p></blockquote><hr><h2 id="_1-初次见面-10-句" tabindex="-1">1. 初次见面（10 句） <a class="header-anchor" href="#_1-初次见面-10-句" aria-label="Permalink to “1. 初次见面（10 句）”">​</a></h2><ol><li><code>Nice to meet you.</code></li><li><code>It&#39;s great to meet you.</code></li><li><code>I&#39;ve heard a lot about you.</code></li><li><code>Thanks for taking the time to meet me.</code></li><li><code>I&#39;m glad we finally met.</code></li><li><code>Please call me [name].</code></li><li><code>Let me introduce myself.</code></li><li><code>It&#39;s a pleasure to meet you.</code></li><li><code>I&#39;ve been looking forward to meeting you.</code></li><li><code>Thanks for being here.</code></li></ol><h2 id="_2-轻松聊天-10-句" tabindex="-1">2. 轻松聊天（10 句） <a class="header-anchor" href="#_2-轻松聊天-10-句" aria-label="Permalink to “2. 轻松聊天（10 句）”">​</a></h2><ol start="11"><li><code>How&#39;s your day going?</code></li><li><code>What have you been up to lately?</code></li><li><code>How was your weekend?</code></li><li><code>Did you do anything fun recently?</code></li><li><code>That&#39;s interesting. Tell me more.</code></li><li><code>That sounds really nice.</code></li><li><code>I&#39;ve had a similar experience.</code></li><li><code>I know what you mean.</code></li><li><code>That must have been exciting.</code></li><li><code>You seem really passionate about that.</code></li></ol><h2 id="_3-聊工作-学习-兴趣-10-句" tabindex="-1">3. 聊工作 / 学习 / 兴趣（10 句） <a class="header-anchor" href="#_3-聊工作-学习-兴趣-10-句" aria-label="Permalink to “3. 聊工作 / 学习 / 兴趣（10 句）”">​</a></h2><ol start="21"><li><code>What do you do?</code></li><li><code>What are you working on these days?</code></li><li><code>What are you studying right now?</code></li><li><code>How did you get into that field?</code></li><li><code>What do you usually do in your free time?</code></li><li><code>What kind of music do you like?</code></li><li><code>Do you have any hobbies?</code></li><li><code>I&#39;ve been learning English recently.</code></li><li><code>I&#39;m trying to improve my speaking skills.</code></li><li><code>I&#39;m interested in technology and self-learning.</code></li></ol><h2 id="_4-发出邀请-10-句" tabindex="-1">4. 发出邀请（10 句） <a class="header-anchor" href="#_4-发出邀请-10-句" aria-label="Permalink to “4. 发出邀请（10 句）”">​</a></h2><ol start="31"><li><code>Would you like to join us?</code></li><li><code>Do you want to grab a coffee sometime?</code></li><li><code>Let&#39;s have lunch together sometime.</code></li><li><code>Would you be free this weekend?</code></li><li><code>How about meeting up next week?</code></li><li><code>Do you want to hang out after work?</code></li><li><code>It would be great to catch up sometime.</code></li><li><code>Let me know if you&#39;d like to come.</code></li><li><code>You&#39;re welcome to join us.</code></li><li><code>I&#39;d love to see you there.</code></li></ol><h2 id="_5-礼貌拒绝与回应-10-句" tabindex="-1">5. 礼貌拒绝与回应（10 句） <a class="header-anchor" href="#_5-礼貌拒绝与回应-10-句" aria-label="Permalink to “5. 礼貌拒绝与回应（10 句）”">​</a></h2><ol start="41"><li><code>I&#39;d love to, but I already have plans.</code></li><li><code>That sounds great, but I may not be available.</code></li><li><code>Maybe next time.</code></li><li><code>Thanks for the invitation.</code></li><li><code>I really appreciate the invite.</code></li><li><code>I&#39;ll let you know soon.</code></li><li><code>I&#39;m not sure yet, but I&#39;ll check my schedule.</code></li><li><code>That sounds like fun.</code></li><li><code>Let&#39;s plan for another time.</code></li><li><code>I hope we can do that soon.</code></li></ol><hr><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to “使用建议”">​</a></h2><ul><li>社交口语不要追求复杂，轻松最重要</li><li><code>11-20</code> 和 <code>31-40</code> 非常实用</li><li>你可以把 <code>28-30</code> 作为自己的固定介绍句</li></ul>',16)])])}const y=o(d,[["render",t]]);export{m as __pageData,y as default};
